        "bloco_id": "Complacência Pulmonar e Tensão Superficial",
        "titulo": "Complacência Pulmonar e Tensão Superficial",
        "disciplina": "Fisiologia II — Respiratória, Renal, Digestiva, Endócrina, Reprodutora, Neuro",
